(function() {
  'use strict';

  if (window.__twitterMediaDLActive) return;
  window.__twitterMediaDLActive = true;

  var JSZIP_CDN = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';
  var PROCESSED_ATTR = 'data-ba-media-dl';

  var STYLES = document.createElement('style');
  STYLES.textContent = [
    '.ba-dl-btn{display:inline-flex;align-items:center;gap:4px;padding:4px 10px;margin:4px;font-size:13px;font-weight:500;color:#1d9bf0;background:transparent;border:1px solid #1d9bf0;border-radius:9999px;cursor:pointer;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif;transition:all .15s}',
    '.ba-dl-btn:hover{background:#1d9bf0;color:#fff}',
    '.ba-dl-btn svg{width:14px;height:14px;fill:currentColor}',
    '.ba-dl-bar{display:flex;flex-wrap:wrap;align-items:center;padding:4px 0}'
  ].join('\n');
  document.head.appendChild(STYLES);

  var DL_ICON = '<svg viewBox="0 0 24 24"><path d="M12 15.575l-4.95-4.95 1.414-1.414L11 11.747V3h2v8.747l2.536-2.536 1.414 1.414L12 15.575zM5 19h14v-4h2v5a1 1 0 01-1 1H4a1 1 0 01-1-1v-5h2v4z"/></svg>';

  function loadJSZip() {
    return new Promise(function(resolve, reject) {
      if (window.JSZip) { resolve(window.JSZip); return; }
      var s = document.createElement('script');
      s.src = JSZIP_CDN;
      s.onload = function() { resolve(window.JSZip); };
      s.onerror = function() { reject(new Error('Failed to load JSZip')); };
      document.head.appendChild(s);
    });
  }

  function getHighResUrl(url) {
    try {
      var u = new URL(url);
      if (u.hostname.includes('twimg.com') && u.searchParams.has('format')) {
        u.searchParams.set('name', 'orig');
        return u.href;
      }
      return url.replace(/&name=[^&]+/, '&name=orig').replace(/\?name=[^&]+/, '?name=orig');
    } catch (_) {
      return url;
    }
  }

  function downloadUrl(url, filename) {
    var a = document.createElement('a');
    a.href = url;
    a.download = filename || '';
    a.target = '_blank';
    a.rel = 'noopener';
    document.body.appendChild(a);
    a.click();
    a.remove();
  }

  async function downloadAsZip(urls, prefix) {
    var JSZip = await loadJSZip();
    var zip = new JSZip();
    for (var i = 0; i < urls.length; i++) {
      try {
        var resp = await fetch(urls[i], { mode: 'cors' });
        var blob = await resp.blob();
        var ext = blob.type.split('/')[1] || 'jpg';
        zip.file(prefix + '_' + (i + 1) + '.' + ext, blob);
      } catch (e) {
        console.warn('[Twitter DL] Failed to fetch:', urls[i], e);
      }
    }
    var zipBlob = await zip.generateAsync({ type: 'blob' });
    var a = document.createElement('a');
    a.href = URL.createObjectURL(zipBlob);
    a.download = prefix + '_media.zip';
    a.click();
    URL.revokeObjectURL(a.href);
  }

  function createButton(text, onClick) {
    var btn = document.createElement('button');
    btn.className = 'ba-dl-btn';
    btn.innerHTML = DL_ICON + ' ' + text;
    btn.addEventListener('click', function(e) {
      e.preventDefault();
      e.stopPropagation();
      onClick(btn);
    });
    return btn;
  }

  function extractImagesFromTweet(article) {
    var imgs = article.querySelectorAll('img[src*="twimg.com/media"]');
    var urls = [];
    imgs.forEach(function(img) {
      var highRes = getHighResUrl(img.src);
      if (urls.indexOf(highRes) === -1) urls.push(highRes);
    });
    return urls;
  }

  function extractVideoFromTweet(article) {
    var video = article.querySelector('video[src]');
    if (video) return video.src;
    var source = article.querySelector('video source[src]');
    if (source) return source.src;
    return null;
  }

  function processTweet(article) {
    if (article.hasAttribute(PROCESSED_ATTR)) return;
    article.setAttribute(PROCESSED_ATTR, 'true');

    var images = extractImagesFromTweet(article);
    var videoUrl = extractVideoFromTweet(article);
    if (images.length === 0 && !videoUrl) return;

    var bar = document.createElement('div');
    bar.className = 'ba-dl-bar';

    if (images.length === 1) {
      bar.appendChild(createButton('Image', function() {
        downloadUrl(images[0], 'twitter_image.jpg');
      }));
    } else if (images.length > 1) {
      images.forEach(function(url, idx) {
        bar.appendChild(createButton('Img ' + (idx + 1), function() {
          downloadUrl(url, 'twitter_image_' + (idx + 1) + '.jpg');
        }));
      });
      bar.appendChild(createButton('ZIP All (' + images.length + ')', function(btn) {
        btn.textContent = 'Packaging...';
        downloadAsZip(images, 'twitter').then(function() {
          btn.innerHTML = DL_ICON + ' ZIP All (' + images.length + ')';
        });
      }));
    }

    if (videoUrl) {
      bar.appendChild(createButton('Video', function() {
        downloadUrl(videoUrl, 'twitter_video.mp4');
      }));
    }

    var actionBar = article.querySelector('[role="group"]');
    if (actionBar && actionBar.parentElement) {
      actionBar.parentElement.insertBefore(bar, actionBar);
    } else {
      article.appendChild(bar);
    }
  }

  function processAll() {
    document.querySelectorAll('article[data-testid="tweet"]').forEach(processTweet);
  }

  processAll();

  var observer = new MutationObserver(function() {
    processAll();
  });
  observer.observe(document.body, { childList: true, subtree: true });

  console.log('[Twitter/X Media Downloader] Active — download buttons added to tweets with media.');
})();
